import { Injectable, inject } from '@angular/core';
import { HttpClient } from '@angular/common/http';
import { Observable } from 'rxjs';
import { API_BASE } from '../api';
import { Product } from '../models';

export interface ProductInput {
  name: string;
  description: string;
  priceCents: number;
  imageUrl: string | null;
  stockQty: number;
}

@Injectable({ providedIn: 'root' })
export class ProductService {
  private readonly http = inject(HttpClient);

  list(q?: string): Observable<Product[]> {
    const query = q ? `?q=${encodeURIComponent(q)}` : '';
    return this.http.get<Product[]>(`${API_BASE}/products${query}`);
  }

  get(id: string): Observable<Product> {
    return this.http.get<Product>(`${API_BASE}/products/${id}`);
  }

  create(input: ProductInput): Observable<Product> {
    return this.http.post<Product>(`${API_BASE}/products`, input);
  }

  update(id: string, input: ProductInput): Observable<Product> {
    return this.http.patch<Product>(`${API_BASE}/products/${id}`, input);
  }

  remove(id: string): Observable<void> {
    return this.http.delete<void>(`${API_BASE}/products/${id}`);
  }
}
